import { useState } from 'react';
import api from '../api/client';

function DonorSearch() {
  const [bloodGroup, setBloodGroup] = useState('');
  const [items, setItems] = useState([]);

  const search = async () => {
    const { data } = await api.get('/donors', { params: { bloodGroup } });
    setItems(data);
  };

  return (
    <div className="container py-4">
      <h2>Donor Search</h2>
      <div className="d-flex gap-2 my-3">
        <input className="form-control" placeholder="Enter blood group (e.g. O+)"
          value={bloodGroup} onChange={(e) => setBloodGroup(e.target.value)} />
        <button className="btn btn-danger" onClick={search}>Search</button>
      </div>
      <div className="row g-3">
        {items.map((d) => (
          <div className="col-md-4" key={d.id}>
            <div className="card p-3 shadow-sm">
              <h6>{d.name}</h6>
              <p className="mb-1"><strong>Group:</strong> {d.bloodGroup}</p>
              <p className="mb-1"><strong>City:</strong> {d.city}</p>
              <p className="mb-0"><strong>Phone:</strong> {d.phone}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default DonorSearch;
